class Solution {
public:
    bool isFascinating(int n) {
        string s = to_string(n);
        string doubled = to_string(2 * n);
        string tripled = to_string(3 * n);
        string concatenated = s + doubled + tripled;
        set<char> digits;
        for (char c : concatenated) {
            if (c == '0') {
                return false;
            }
            digits.insert(c);
        }
        return digits.size() == 9;
    }
};
